using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder – success paths

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 25m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(45m, order.Total); // 10*2 + 25*1
        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_ReturnsOrderWithSingleItem()
    {
        var items = CreateItems(("Widget", 15m, 3));

        var order = _service.CreateOrder("cust-2", items);

        Assert.AreEqual(45m, order.Total);
        var single = Assert.ContainsSingle(order.Items);
        Assert.AreEqual("Widget", single.ProductName);
    }

    [TestMethod]
    public void CreateOrder_AssignsUniqueId()
    {
        var items = CreateItems(("A", 1m, 1));

        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", CreateItems(("B", 2m, 1)));

        Assert.IsNotNull(order1.Id);
        Assert.IsNotNull(order2.Id);
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToUtcNow()
    {
        var before = DateTime.UtcNow;

        var order = _service.CreateOrder("cust-1", CreateItems(("X", 5m, 1)));

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    #endregion

    #region CreateOrder – error paths

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));

        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        var created = _service.CreateOrder("cust-1", CreateItems(("Widget", 10m, 1)));

        var found = _service.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAll()
    {
        _service.CreateOrder("cust-A", CreateItems(("W1", 5m, 1)));
        _service.CreateOrder("cust-A", CreateItems(("W2", 10m, 1)));
        _service.CreateOrder("cust-B", CreateItems(("W3", 15m, 1)));

        var orders = _service.GetOrdersByCustomer("cust-A");

        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var orders = _service.GetOrdersByCustomer("no-such-customer");

        Assert.IsEmpty(orders);
    }

    #endregion

    #region Data-driven total calculation

    [TestMethod]
    [DynamicData(nameof(TotalTestData))]
    public void CreateOrder_CalculatesTotalCorrectly(
        string name, decimal price, int qty, decimal expectedTotal)
    {
        var order = _service.CreateOrder("cust-1", CreateItems((name, price, qty)));

        Assert.AreEqual(expectedTotal, order.Total);
    }

    public static IEnumerable<(string name, decimal price, int qty, decimal expectedTotal)> TotalTestData =>
    [
        ("Single", 10m, 1, 10m),
        ("Multiple", 7.50m, 4, 30m),
        ("Expensive", 999.99m, 2, 1999.98m),
    ];

    #endregion
}

